{
  "name": "custom-auth-ui",
  "type": "module",
  "workspaces": [".wasp/out/*", ".wasp/out/sdk/wasp"],
  "dependencies": {
    "react": "^19.2.1",
    "react-dom": "^19.2.1",
    "react-router": "^7.12.0"
  },
  "devDependencies": {
    "@types/react": "^19.2.7",
    "@types/react-dom": "^19.2.3",
    "prisma": "5.19.1",
    "typescript": "5.8.2",
    "vite": "^7.0.6"
  }
}

import { logout } from 'wasp/client/auth';
import { type AuthUser } from 'wasp/auth';
import './Main.css';

export function MainPage({ user }: { user: AuthUser }) {
  // Wasp's user object has identities.
  // Based on the error message, the identity key is 'username'.
  const username = user.identities.username?.id || 'unknown';

  return (
    <main className="container">
      <h1>Main Page</h1>
      <p>You are logged in as <strong>{username}</strong></p>
      <button onClick={logout}>Logout</button>
    </main>
  );
}

import React, { useState } from 'react';
import { Link } from 'react-router';
import { signup, login } from 'wasp/client/auth';

export const SignupPage = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');

  const handleSubmit = async (event: React.FormEvent) => {
    event.preventDefault();
    try {
      await signup({ username, password });
      await login({ username, password });
    } catch (error: any) {
      alert(error.message || 'An error occurred during signup');
    }
  };

  return (
    <div style={{ padding: '2rem' }}>
      <h1>Sign Up</h1>
      <form onSubmit={handleSubmit}>
        <div>
          <label htmlFor="username">Username</label>
          <input
            id="username"
            type="text"
            value={username}
            onChange={(e) => setUsername(e.target.value)}
            required
          />
        </div>
        <div>
          <label htmlFor="password">Password</label>
          <input
            id="password"
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required
          />
        </div>
        <button type="submit">Sign Up</button>
      </form>
      <p>
        Already have an account? <Link to="/login">Log in</Link>
      </p>
    </div>
  );
};

